import { useLocation, useNavigate } from "react-router-dom";
import { motion } from "framer-motion";
import basiclogo1 from "../assets/basiclogo1.png";

export default function ReportPage() {
  const { state } = useLocation();
  const navigate = useNavigate();

  if (!state?.reportUrl) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-black text-white">
        No report found
      </div>
    );
  }

  const { reportUrl } = state;

  return (
    <div className="min-h-screen bg-black text-white flex flex-col items-center justify-center px-4">
      {/* HEADER */}
      <motion.div 
        initial={{ y: -50, opacity: 0 }} 
        animate={{ y: 0, opacity: 1 }} 
        transition={{ type: "spring", stiffness: 100, damping: 20 }}
        className="absolute top-6 left-6 flex items-center gap-2"
      >
        <img src={basiclogo1} className="w-10 h-10" alt="CollegeReviewZ" />
        <span className="text-xl font-bold">
          CollegeReview<span className="text-indigo-500">Z</span>
        </span>
      </motion.div>

      {/* CARD */}
      <motion.div
        initial={{ x: 50, opacity: 0 }}
        animate={{ x: 0, opacity: 1 }}
        transition={{ type: "spring", stiffness: 100, damping: 20 }}
        className="bg-slate-900 rounded-3xl p-10 max-w-md w-full text-center shadow-2xl"
      >
        <h1 className="text-3xl font-extrabold mb-4 text-indigo-400">
          Assessment Completed 🎉
        </h1>

        <p className="text-gray-300 mb-8">
          Your career report is ready.
        </p>

        {/* ✅ USE BACKEND URL DIRECTLY */}
        {/* ✅ USE BACKEND URL DIRECTLY */}
        <a
          href={reportUrl}
          target="_blank"
          rel="noopener noreferrer"
          className="relative overflow-hidden group block w-full py-4 mb-4 rounded-xl bg-gradient-to-r from-[#007ACC] to-[#47B5FF] font-bold text-white shadow-lg hover:shadow-xl transition-all"
        >
          <span className="absolute inset-0 w-0 bg-white transition-all duration-[250ms] ease-out group-hover:w-full"></span>
          <span className="relative z-10 flex items-center justify-center gap-2 group-hover:text-[#002D62] transition-colors duration-300">
            📄 Download PDF Report
          </span>
        </a>

        <button
          onClick={() => navigate("/")}
          className="relative overflow-hidden group w-full py-4 rounded-xl bg-white font-bold text-[#002D62] shadow-lg hover:shadow-xl transition-all"
        >
          <span className="absolute inset-0 w-0 bg-gradient-to-r from-[#007ACC] to-[#47B5FF] transition-all duration-[250ms] ease-out group-hover:w-full"></span>
          <span className="relative z-10 flex items-center justify-center gap-2 group-hover:text-white transition-colors duration-300">
            🔁 Take Assessment Again
          </span>
        </button>
      </motion.div>
    </div>
  );
}
